class Stack:
 def __init__(self):
 self.stack = []

 def push(self, element):
 self.stack.append(element)

 def pop(self):
 if not self.isEmpty():
 return self.stack.pop()
 else:
 return None

 def isEmpty(self):
 return len(self.stack) == 0

# Example usage:
stack = Stack()
stack.push(1)
stack.push(2)
print(stack.pop()) # Output: 2

#include <stdio.h>

#define MAX_SIZE 5

int queue[MAX_SIZE];
int front = 0;
int rear = 0;

void enqueue(int element) {
 if (rear < MAX_SIZE) {
 queue[rear] = element;
 rear++;
 } else {
 printf("Queue is full\n");
 }
}

int dequeue() {
 if (front < rear) {
 int element = queue[front];
 front++;
 return element;
 } else {
 printf("Queue is empty\n");
 return -1;
 }
}

// Example usage:
enqueue(1);
enqueue(2);
printf("Dequeued element: %d\n", dequeue()); // Output: 1
